svg.script:

// Physics and State
let state = {
    'power': 40, // 0 to 100
    'tail': 0    // 0 to 800 (simulated lbs)
};

let lastTime = 0;
let rotorAngle = 0;
let fuselageAngle = 0;
let fuselageVelocity = 0;
let tailRotorSpin = 0;

const SLIDER_WIDTH = 350;
let activeSlider = null;

const sliderConfig = {
    'power': { min: 0, max: 100 },
    'tail': { min: 0, max: 800 }
};

function initSimulation() {
    updateVisuals();
    requestAnimationFrame(animationLoop);
}

function getClientX(evt) {
    if (evt.touches && evt.touches.length > 0) return evt.touches[0].clientX;
    if (evt.changedTouches && evt.changedTouches.length > 0) return evt.changedTouches[0].clientX;
    return evt.clientX;
}
function getClientY(evt) {
    if (evt.touches && evt.touches.length > 0) return evt.touches[0].clientY;
    if (evt.changedTouches && evt.changedTouches.length > 0) return evt.changedTouches[0].clientY;
    return evt.clientY;
}

function startDrag(evt, id) {
    activeSlider = id;
    updateDrag(evt);
}
function startDragTouch(evt, id) {
    evt.preventDefault();
    activeSlider = id;
    updateDrag(evt);
}

function onMouseMove(evt) {
    if (activeSlider) updateDrag(evt);
}
function onMouseUp(evt) {
    activeSlider = null;
}
function onTouchMove(evt) {
    if (activeSlider) { evt.preventDefault(); updateDrag(evt); }
}
function onTouchEnd(evt) {
    activeSlider = null;
}

function updateDrag(evt) {
    const svg = document.getElementById('main-svg');
    const pt = svg.createSVGPoint();
    pt.x = getClientX(evt);
    pt.y = getClientY(evt);
    const svgP = pt.matrixTransform(svg.getScreenCTM().inverse());

    let localX = svgP.x - 770;
    if (localX < 0) localX = 0;
    if (localX > SLIDER_WIDTH) localX = SLIDER_WIDTH;

    const conf = sliderConfig[activeSlider];
    state[activeSlider] = conf.min + (localX / SLIDER_WIDTH) * (conf.max - conf.min);

    document.getElementById('track-' + activeSlider).setAttribute('x2', localX);
    document.getElementById('thumb-' + activeSlider).setAttribute('cx', localX);

    updateVisuals();
}

function updateVisuals() {
    document.getElementById('val-power').textContent = Math.round(state.power) + '%';
    document.getElementById('val-tail').textContent = Math.round(state.tail) + ' lbs';

    // Torque is proportional to power
    const torqueVal = state.power * 10; 
    const tailMoment = state.tail * 2.5; // Leverage factor

    document.getElementById('met-torque').textContent = Math.round(torqueVal) + ' Nm';
    document.getElementById('met-moment').textContent = Math.round(tailMoment) + ' Nm';

    // Scale Tail Force Arrow
    const tailLen = (state.tail / 800) * 80;
    document.getElementById('tail-thrust-line').setAttribute('y2', -tailLen);

    // Adjust label opacity based on thrust
    document.getElementById('tail-force-group').style.opacity = state.tail > 5 ? 1 : 0.2;
}

function animationLoop(timestamp) {
    if (!lastTime) lastTime = timestamp;
    const dt = (timestamp - lastTime) / 16;
    lastTime = timestamp;

    // 1. Calculate Fuselage Physics
    // Torque Reaction - Tail Moment
    const torqueVal = state.power * 10;
    const tailMoment = state.tail * 2.5;

    // Resulting Rotational Acceleration
    const netTorque = torqueVal - tailMoment;

    // Update Velocity (with rotational damping/friction)
    fuselageVelocity += netTorque * 0.001 * dt;
    fuselageVelocity *= Math.pow(0.95, dt); 

    fuselageAngle += fuselageVelocity * dt;

    // Apply rotation to the whole group
    document.getElementById('heli-group').setAttribute('transform', `rotate(${fuselageAngle})`);

    // 2. Animate Rotor Spins
    const mainSpeed = (state.power * 0.3) + 1;
    rotorAngle = (rotorAngle + mainSpeed * dt) % 360;
    document.getElementById('main-rotor-spin').setAttribute('transform', `rotate(${rotorAngle})`);

    const tailSpeed = (state.power * 0.1) + (state.tail * 0.05);
    tailRotorSpin = (tailRotorSpin + tailSpeed * dt) % 360;
    const tailScale = Math.cos(tailRotorSpin * Math.PI / 180);
    document.getElementById('tail-rotor-spin').setAttribute('transform', `translate(-222, 0) scale(1, ${tailScale})`);

    // 3. Update State Text
    const stateText = document.getElementById('met-state');
    if (Math.abs(fuselageVelocity) < 0.2) {
        stateText.textContent = "STABLE";
        stateText.setAttribute('fill', '#10b981');
    } else {
        stateText.textContent = fuselageVelocity > 0 ? "SPINNING (CW)" : "SPINNING (CCW)";
        stateText.setAttribute('fill', '#ef4444');
    }

    requestAnimationFrame(animationLoop);
}
